import {
    useMutation,
    useQuery,
    useQueryClient,
    type UseMutationOptions,
    type UseQueryOptions,
} from '@tanstack/react-query';
import {
    type Guid,
    type LeaveBalanceCreateDTO,
    type LeaveBalanceDTO,
    type LeaveCoveredAssignDTO,
    type LeaveCoveredCreateDTO,
    type LeaveCoveredDTO,
    type LeaveCoveredListParams,
    type LeaveCoveredVerifyDTO,
    type LeaveCreateDTO,
    type LeaveDTO,
    type LeaveListParams,
    type LeaveRejectDTO,
    type LeaveStructureDTO,
    type LeaveStructureInputDTO,
    type LeaveStructureListParams,
    leaveService,
} from '../../../api/leaveService';
import { leaveBalanceService } from '@/api/leaveBalanceService';
import type { Pagination } from '@/types/api';

export const leaveQueryKeys = {
    all: ['leave'] as const,
    leavesList: (params: LeaveListParams = {}) => ['leave', 'leaves', 'list', params] as const,
    leaveDetail: (id: Guid) => ['leave', 'leaves', 'detail', id] as const,
    balanceByUser: (userProfileId: Guid) => ['leave', 'balance', 'user', userProfileId] as const,
    balanceByFinancialYear: (userProfileId: Guid, financialYear: string) =>
        ['leave', 'balance', 'fy', userProfileId, financialYear] as const,
    coveredList: (params: LeaveCoveredListParams = {}) => ['leave', 'covered', 'list', params] as const,
    coveredDetail: (id: Guid) => ['leave', 'covered', 'detail', id] as const,
    structureList: (params: LeaveStructureListParams = {}) => ['leave', 'structure', 'list', params] as const,
    structureByUser: (userProfileId: Guid) => ['leave', 'structure', 'user', userProfileId] as const,
    monthlyLeave: (userProfileId: Guid, month: number, year: number) =>
        ['leave', 'structure', 'monthly-leave', userProfileId, month, year] as const,
};

export function useLeavesListQuery(
    params: LeaveListParams = {},
    options?: Omit<UseQueryOptions<Pagination<LeaveDTO>>, 'queryKey' | 'queryFn'>
) {
    return useQuery({
        queryKey: leaveQueryKeys.leavesList(params),
        queryFn: () => leaveService.leaves.list(params),
        ...options,
    });
}

export function useLeaveDetailQuery(
    id: Guid,
    options?: Omit<UseQueryOptions<LeaveDTO>, 'queryKey' | 'queryFn'>
) {
    return useQuery({
        queryKey: leaveQueryKeys.leaveDetail(id),
        queryFn: () => leaveService.leaves.getById(id),
        enabled: Boolean(id),
        ...options,
    });
}

export function useLeaveActionMutation<TData = LeaveDTO, TVariables = Guid>(
    mutationFn: (variables: TVariables) => Promise<TData>,
    options?: Omit<UseMutationOptions<TData, unknown, TVariables>, 'mutationFn'>
) {
    const queryClient = useQueryClient();
    return useMutation({
        mutationFn,
        onSuccess: async (data, variables, onMutateResult, context) => {
            await queryClient.invalidateQueries({ queryKey: leaveQueryKeys.all });
            await options?.onSuccess?.(data, variables, onMutateResult, context);
        },
        ...options,
    });
}

